cd Z:/project/ai-coding/train-recorder/tests/e2e && node -e "
const data = JSON.parse(require('fs').readFileSync('results/test-results.json','utf-8'));
let total = 0, passed = 0, failed = 0, skipped = 0, notRun = 0;
const results = [];

function walkSuites(suites) {
  for (const suite of suites) {
    if (suite.specs) {
      for (const spec of suite.specs) {
        total++;
        if (spec.tests && spec.tests.length > 0 && spec.tests[0].results && spec.tests[0].results.length > 0) {
          const result = spec.tests[0].results[0];
          const status = result.status || 'unknown';
          if (status === 'passed') passed++;
          else if (status === 'failed' || status === 'timedOut') failed++;
          else if (status === 'skipped') skipped++;
          else notRun++;

          const tcMatch = spec.title.match(/TC-[A-Z]*-\d+/);
          const tcId = tcMatch ? tcMatch[0] : spec.title;
          const errors = result.errors ? result.errors.map(e => e.message).join('\\n') : '';
          results.push({ tcId, title: spec.title, status, duration: result.duration, errors: errors.substring(0, 200) });
        } else {
          notRun++;
          const tcMatch = spec.title.match(/TC-[A-Z]*-\d+/);
          const tcId = tcMatch ? tcMatch[0] : spec.title;
          results.push({ tcId, title: spec.title, status: 'did_not_run', duration: 0, errors: '' });
        }
      }
    }
    if (suite.suites) walkSuites(suite.suites);
  }
}
walkSuites(data.suites);
console.log(JSON.stringify({summary: {total, passed, failed, skipped, notRun}, results}, null, 2));
" 2>&1

